#include <stdio.h>
#include <unistd.h>
#include <sys/wait.h>
#include <stdlib.h>

int main() {
    pid_t pid;
    int status;

    printf("Parent process (PID: %d) starting...\n", getpid());

    pid = fork(); // Create child process

    if (pid < 0) {
        // Error occurred
        perror("fork failed");
        exit(1);
    }
    else if (pid == 0) {
        // Child process
        printf("Child process: PID = %d, Parent PID = %d\n", 
               getpid(), getppid());
        printf("Child executing new program...\n");

        // Replace with new program using exec
        // execlp("ls", "ls", "-l", NULL);

        exit(42); // Exit with status 42
    }
    else {
        // Parent process
        printf("Parent: Created child with PID %d\n", pid);

        // Wait for child to complete
        wait(&status);

        if (WIFEXITED(status)) {
            printf("Child exited with status: %d\n", WEXITSTATUS(status));
        }
        printf("Parent process completed\n");
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

// Process Control Block structure
typedef struct {
    int pid;           // Process ID
    int ppid;          // Parent Process ID
    char state[20];    // Process state
    int pc;            // Program counter
    int registers[5];  // CPU registers
    int priority;      // Process priority
    int program[10];   // Simple program instructions
    int program_size;
} PCB;

// Initialize a new process
PCB* create_process(int pid, int ppid, int priority) {
    PCB* pcb = (PCB*)malloc(sizeof(PCB));
    pcb->pid = pid;
    pcb->ppid = ppid;
    strcpy(pcb->state, "NEW");
    pcb->pc = 0;
    pcb->priority = priority;
    pcb->program_size = 0;

    // Initialize registers
    for(int i = 0; i < 5; i++) {
        pcb->registers[i] = 0;
    }

    return pcb;
}

// Context switch: save current process state
void save_context(PCB* pcb, int pc, int* regs) {
    pcb->pc = pc;
    for(int i = 0; i < 5; i++) {
        pcb->registers[i] = regs[i];
    }
}

// Context switch: load process state
void load_context(PCB* pcb, int* pc, int* regs) {
    *pc = pcb->pc;
    for(int i = 0; i < 5; i++) {
        regs[i] = pcb->registers[i];
    }
}

// Simulate process state change
void change_state(PCB* pcb, char* new_state) {
    strcpy(pcb->state, new_state);
}

int main() {
    // Create two processes
    PCB* p1 = create_process(100, 1, 5);
    PCB* p2 = create_process(101, 1, 3);

    // Load programs
    p1->program[0] = 10; p1->program[1] = 20; p1->program_size = 2;
    p2->program[0] = 30; p2->program[1] = 40; p2->program_size = 2;

    printf("Created Process 1 (PID: %d, Priority: %d)\n", p1->pid, p1->priority);
    printf("Created Process 2 (PID: %d, Priority: %d)\n", p2->pid, p2->priority);

    // Simulate scheduling
    change_state(p1, "READY");
    change_state(p2, "READY");

    // Execute P1
    change_state(p1, "RUNNING");
    printf("P1 executing instruction at PC=%d\n", p1->pc);
    p1->pc++;

    // Context switch to P2
    printf("Context switch: Saving P1, Loading P2\n");
    change_state(p1, "READY");
    change_state(p2, "RUNNING");

    // Execute P2
    printf("P2 executing instruction at PC=%d\n", p2->pc);

    change_state(p2, "TERMINATED");
    printf("P2 completed\n");

    free(p1);
    free(p2);

    return 0;
}
